parameters.command:
=cd "/data/shared/{{ $execution.id }}/kompose"
for f in *.yaml; do
  echo "# FILE: $f";
  echo "---";
  cat "$f";
  echo "";
done

=set -eu

ROOT="/data/shared/{{ $execution.id }}/k8s/prod"
mkdir -p "$ROOT"

cat > "$ROOT/model.json" <<'__MODEL_JSON__'
{{ JSON.stringify($json.output) }}
__MODEL_JSON__

export ROOT

node - <<'NODE'
const fs = require('fs');
const path = require('path');

const root = process.env.ROOT;
const data = JSON.parse(fs.readFileSync(path.join(root, 'model.json'), 'utf8'));

for (const f of data.files) {
  const outPath = path.join(root, f.path);
  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  fs.writeFileSync(outPath, f.content, 'utf8');
}

console.log('WROTE_DIR=', root);
console.log('COUNT=', data.files.length);
NODE
rm -f "$ROOT/model.json"

=cd "/data/shared/{{ $execution.id }}"
for f in k8s/prod/*.yaml; do
  echo "# FILE: $f";
  echo "---";
  cat "$f";
  echo "";
done
